const account = $input.first().json;
const hours = account.hours_since_activity;

let escalation_level = 'L1';
let notify_targets = [account.csm_slack_id];
let escalation_label = 'CSM Only';

if (hours >= 120) {
  escalation_level = 'L4';
  notify_targets = [account.csm_slack_id, '#cs-managers', '#sales-team'];
  escalation_label = 'CSM + CS Manager + Sales – RESCUE CALL';
} else if (hours >= 96) {
  escalation_level = 'L3';
  notify_targets = [account.csm_slack_id, '#cs-managers'];
  escalation_label = 'CSM + CS Manager';
} else if (hours >= 72) {
  escalation_level = 'L2';
  notify_targets = [account.csm_slack_id, '#cs-managers'];
  escalation_label = 'CSM + CS Manager';
} else if (hours >= 48) {
  escalation_level = 'L1';
  notify_targets = [account.csm_slack_id];
  escalation_label = 'CSM Only – Step-Specific';
} else {
  escalation_level = 'L0';
  notify_targets = [account.csm_slack_id];
  escalation_label = 'CSM Only – Day 1';
}

return [{
  json: {
    ...account,
    escalation_level,
    escalation_label,
    notify_targets
  }
}];

const template = $input.first().json;
const account = $('Set Escalation Level').first().json;

const subject = (template['Subject Line'] || 'Your onboarding needs attention')
  .replace('{{company_name}}', account.company_name)
  .replace('{{stuck_step}}', account.current_stuck_step);

const body = (template['Body HTML'] || '<p>Hi, we noticed you may need help with onboarding.</p>')
  .replace(/{{company_name}}/g, account.company_name)
  .replace(/{{stuck_step}}/g, account.current_stuck_step)
  .replace(/{{trial_end}}/g, account.trial_end)
  .replace(/{{csm_name}}/g, account.account_owner || 'Your Customer Success Manager');

return [{
  json: {
    ...account,
    template_name:    template['Step Name'],
    template_subject: subject,
    template_body:    body,
    to_email:         'admin@' + account.domain,
    intervention_type: template['Intervention Type'] || 'Email'
  }
}];

const account = $('Merge Template with Account').first().json;

const subject = `[OnboardIQ] Intervention Sent – ${account.company_name} stalled on ${account.current_stuck_step}`;

const body = `<html><body style="font-family:sans-serif;max-width:600px;"><h3>Onboarding Intervention Sent</h3><table style="border-collapse:collapse;width:100%;"><tr><td style="padding:6px;font-weight:bold;">Account</td><td style="padding:6px;">${account.company_name}</td></tr><tr><td style="padding:6px;font-weight:bold;">Stuck Step</td><td style="padding:6px;">${account.current_stuck_step}</td></tr><tr><td style="padding:6px;font-weight:bold;">Hours Stalled</td><td style="padding:6px;">${account.hours_since_activity}h</td></tr><tr><td style="padding:6px;font-weight:bold;">Escalation</td><td style="padding:6px;">${account.escalation_label}</td></tr><tr><td style="padding:6px;font-weight:bold;">Email Subject Sent</td><td style="padding:6px;">${account.template_subject}</td></tr><tr><td style="padding:6px;font-weight:bold;">Health Score</td><td style="padding:6px;">${account.health_score}/100</td></tr></table><p style="color:#666;font-size:12px;">Logged automatically by OnboardIQ.</p></body></html>`;

return [{ json: { ...account, csm_notify_subject: subject, csm_notify_body: body } }];

const body = $input.first().json.body || $input.first().json;
const trialStart = new Date();
const trialEnd = new Date(trialStart.getTime() + 14 * 24 * 60 * 60 * 1000);

return [{
  json: {
    company_name: body.company_name,
    domain: body.domain,
    plan: body.plan || 'Trial',
    account_id: body.account_id,
    csm_email: body.csm_email || 'cs@yourcompany.com',
    account_owner: body.csm_name || 'Unassigned',
    trial_start: (trialStart.getMonth()+1) + '/' + trialStart.getDate() + '/' + trialStart.getFullYear(),
    trial_end: (trialEnd.getMonth()+1) + '/' + trialEnd.getDate() + '/' + trialEnd.getFullYear(),
    onboarding_status: 'Onboarding',
    health_score: 100,
    current_stuck_step: '',
    hours_since_last_activity: 0,
    milestones: [
      { step_name: 'Account Setup',      step_order: 1, is_blocking: true  },
      { step_name: 'API Setup',          step_order: 2, is_blocking: true  },
      { step_name: 'Team Invite',        step_order: 3, is_blocking: false },
      { step_name: 'First Integration',  step_order: 4, is_blocking: true  },
      { step_name: 'First Report',       step_order: 5, is_blocking: false },
      { step_name: 'Dashboard Reviewed', step_order: 6, is_blocking: false }
    ]
  }
}];

const account = $input.first().json;
const airtableRecordId = account.id;
const milestones = $('Prepare Account Data').first().json.milestones;

return milestones.map(m => ({
  json: {
    account_record_id: airtableRecordId,
    step_name: m.step_name,
    step_order: m.step_order,
    status: 'Pending',
    is_blocking: m.is_blocking,
    completed_at: null,
    hours_to_complete: null
  }
}));

const milestones = $input.all().map(i => i.json);
const total = milestones.length;
const completed = milestones.filter(m => m['status'] === 'Completed').length;
const interventionsReceived = parseInt($('Milestone Completion Webhook').first().json.body.interventions_count || 0);
const completionRatio = total > 0 ? completed / total : 0;
const healthScore = Math.max(0, Math.round(completionRatio * 100) - (interventionsReceived * 10));

return [{
  json: {
    account_record_id: $('Milestone Completion Webhook').first().json.body.account_record_id,
    milestones_completed: completed,
    total_milestones: total,
    completion_pct: Math.round(completionRatio * 100),
    health_score: healthScore,
    last_activity: new Date().toISOString()
  }
}];

const interventions = $input.all().map(i => i.json).filter(i => i['outcome'] !== undefined);
const accounts = $('Fetch All Accounts').all().map(i => i.json);

const totalAccounts = accounts.length;
const converted = accounts.filter(a => a['onboarding_status'] === 'Converted').length;
const churned = accounts.filter(a => a['onboarding_status'] === 'Churned').length;
const stalled = accounts.filter(a => a['onboarding_status'] === 'Stalled').length;
const completed = accounts.filter(a => a['onboarding_status'] === 'Completed').length;

const conversionRate = totalAccounts > 0 ? Math.round((converted / totalAccounts) * 100) : 0;
const churnRate = totalAccounts > 0 ? Math.round((churned / totalAccounts) * 100) : 0;

const successfulInterventions = interventions.filter(i => i['outcome'] === 'Successful').length;
const totalInterventions = interventions.length;
const interventionSuccessRate = totalInterventions > 0
  ? Math.round((successfulInterventions / totalInterventions) * 100) : 0;

const avgHealth = accounts.length > 0
  ? Math.round(accounts.reduce((s, a) => s + (a['health_score'] || 0), 0) / accounts.length) : 0;

return [{
  json: {
    week_ending: new Date().toISOString().split('T')[0],
    total_accounts: totalAccounts,
    converted, churned, stalled, completed,
    conversion_rate_pct: conversionRate,
    churn_rate_pct: churnRate,
    total_interventions: totalInterventions,
    successful_interventions: successfulInterventions,
    intervention_success_rate: interventionSuccessRate,
    avg_health_score: avgHealth
  }
}];

const account = $('Loop Expiring Accounts').first().json;
const milestones = $input.all().map(i => i.json);

const completed = milestones.filter(m => m['status'] === 'Completed');
const remaining = milestones.filter(m => m['status'] === 'Pending');

const completedList = completed.map(m => m['step_name']).join(', ') || 'None';
const remainingList = remaining.map(m => m['step_name']).join(', ') || 'None';

const completionPct = milestones.length > 0
  ? Math.round((completed.length / milestones.length) * 100)
  : 0;

return [{
  json: {
    record_id:            account.id,
    company_name:         account['company_name'],
    domain:               account['domain'],
    plan:                 account['plan'],
    trial_end:            account['trial_end'],
    csm_email:            account['csm_email'] || 'cs@yourcompany.com',
    milestones_completed: completed.length,
    total_milestones:     milestones.length,
    completion_pct:       completionPct,
    completed_steps:      completedList,
    remaining_steps:      remainingList,
    health_score:         account['health_score'] || 0,
    needs_rescue:         completionPct < 50
  }
}];

const account = $('Summarize Onboarding Progress1').first().json;

const pitch = `${account.company_name} has completed ${account.milestones_completed} of ${account.total_milestones} onboarding steps including ${account.completed_steps}. Upgrading to a paid plan ensures uninterrupted access and unlocks ${account.remaining_steps} — the features that drive the most long-term value for teams like yours.`;

return [{ json: { ...account, message: { content: [{ text: pitch }] } } }];

return $input.all().map(item => {
  const account = item.json;
  const hoursSince = account['hours_since_last_activity'] || 0;

  return {
    json: {
      record_id:            account.id,
      company_name:         account['company_name'],
      domain:               account['domain'],
      plan:                 account['plan'],
      trial_end:            account['trial_end'],
      current_stuck_step:   account['current_stuck_step'] || 'Account Setup',
      hours_since_activity: hoursSince,
      csm_email:            account['csm_email'] || 'cs@yourcompany.com',
      health_score:         account['health_score'] || 100,
      account_owner:        account['account_owner'] || 'CSM'
    }
  };
});
